class Solution:
    def shortestMatchingSubstring(self, s: str, p: str) -> int:
        p1, p2 = p.replace('*', '.*'), p.replace('*', '')
        m, n = len(p1), len(s)
        dp = [[0] * (n + 1) for _ in range(m + 1)]
        res = n + 1
        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if p1[i - 1] == s[j - 1] or p1[i - 1] == '.':
                    dp[i][j] = dp[i - 1][j - 1] + 1
                    if i == m:
                        res = min(res, j)
                else:
                    dp[i][j] = 0
        return res if res <= n else -1
